{"name":"SwitchAirPurifierToAutoAndSay","cron":"","period":0,"code":"if ((#Study_AQ).AirQualitySensor_CarbonDioxide >= 1000 and (#Study_AP).AirPurifier_AirPurifierMode == "sleep") {
    (#Study_AP).AirPurifier_SetAirPurifierMode("auto")
    (#Study_Speaker).Speaker_Speak("Switching the air purifier to auto mode")
}"}

{"name":"AdjustAirConditionerModeBasedOnTemperature","cron":"","period":1800000,"code":"prevTemp := (#AirQualitySensor).AirQualitySensor_Temperature
currTemp := (#AirQualitySensor).AirQualitySensor_Temperature
if (prevTemp >= 30 and currTemp < 30) {
    (#AirConditioner).AirConditioner_SetAirConditionerMode("cool")
} else if (prevTemp < 30 and currTemp >= 30) {
    (#AirConditioner).AirConditioner_SetAirConditionerMode("auto")
}
prevTemp = currTemp"}

