{"name":"IncreaseLightBrightnessOnMotion","cron":"","period":100,"code":"prev := (#MotionSensor).MotionSensor_Motion
curr = (#MotionSensor).MotionSensor_Motion
if (prev == false and curr == true) {
    curr_brightness := (#Light).Light_CurrentBrightness
    if (curr_brightness < 100) {
        (#Light).Light_MoveToBrightness(curr_brightness + 10, 0)
    }
}
prev = curr"}

