{"name":"CheckSafeAndAnnounce","cron":"","period":300000,"code":"prev := (#Entrance #Door).Door_DoorState
curr = (#Entrance #Door).Door_DoorState
if (prev != "open" and curr == "open") {
    wait until ((#Safe).Safe_SafeState != "locked")
