}
prev = curr"}

{"name":"AnnounceSmokeAndEmailWarning","cron":"","period":0,"code":"wait until ((#SmokeDetector).SmokeDetector_Smoke == true)
(#Speaker).Speaker_Speak("Smoke detected!")
repeat every 5 MIN {
    (#EmailProvider).EmailProvider_SendMail("test@example.com", "Fire Warning", "A fire has occurred. Please evacuate.")
}"}

{"name":"SetEvenRobotsToAutoMode","cron":"","period":100,"code":"prev := all(#Even #RobotVacuumCleaner).RobotVacuumCleaner_RobotVacuumCleanerMode
